class scoped_restore_current_inferior
{
public:
  scoped_restore_current_inferior ()
    : m_saved_inf (current_inferior ())
  {}

  ~scoped_restore_current_inferior ()
  { set_current_inferior (m_saved_inf); }

  /* Disable copy.  */
  scoped_restore_current_inferior
    (const scoped_restore_current_inferior &) = delete;
  void operator=
    (const scoped_restore_current_inferior &) = delete;

private:
  inferior *m_saved_inf;
}

